from __future__ import annotations
import json
import uuid
from datetime import datetime, timezone
from dataclasses import dataclass, asdict
from typing import Any

@dataclass
class OutboxEntry:
    entry_id: str
    event_type: str
    payload: dict[str, Any]
    created_at: str
    published: bool = False
    published_at: str = ""

class MDMOutbox:
    """In-process outbox — in production, backed by the same DB as the catalog
    (e.g. a 'mdm_outbox' table) to guarantee transactional writes."""

    def __init__(self) -> None:
        self._entries: list[OutboxEntry] = []

    def append(self, event_type: str, payload: dict[str, Any]) -> OutboxEntry:
        entry = OutboxEntry(
            entry_id=str(uuid.uuid4()),
            event_type=event_type,
            payload=payload,
            created_at=datetime.now(timezone.utc).isoformat(),
        )
        self._entries.append(entry)
        return entry

    def unpublished(self) -> list[OutboxEntry]:
        return [e for e in self._entries if not e.published]

    def mark_published(self, entry_id: str) -> None:
        for e in self._entries:
            if e.entry_id == entry_id:
                e.published = True
                e.published_at = datetime.now(timezone.utc).isoformat()

class OutboxRelay:
    """Polls outbox; publishes to event bus; marks entries as published."""

    def __init__(self, outbox: MDMOutbox, publish_fn) -> None:
        self._outbox = outbox
        self._publish = publish_fn

    def relay_pending(self) -> int:
        pending = self._outbox.unpublished()
        for entry in pending:
            self._publish(entry.event_type, entry.payload)
            self._outbox.mark_published(entry.entry_id)
        return len(pending)

from __future__ import annotations
import logging
from dataclasses import dataclass
from typing import Callable, Iterable

log = logging.getLogger(__name__)

@dataclass
class DriftReport:
    orphaned_chunks: int      # chunks with golden_id not in MDM catalog
    stale_metadata: int       # chunks where classification_label/permitted_apps differ from MDM
    missing_chunks: int       # golden records with ACTIVE status but zero chunks in index
    reconciled_events: list[dict]

def reconcile_mdm_with_index(
    catalog_records: Iterable[dict],   # all ACTIVE SourceRecord dicts
    vector_store,
    enqueue_event: Callable[[str, dict], None],
) -> DriftReport:
    """Full reconciliation pass. Produces fix events for the sync worker."""
    catalog = {r["golden_id"]: r for r in catalog_records}
    catalog_ids = set(catalog)

    orphaned = stale = missing = 0
    events = []

    # Check every golden_id in the catalog
    for golden_id, record in catalog.items():
        chunks = vector_store.fetch_chunks_for(golden_id)
        if not chunks and record["status"] == "active":
            missing += 1
            log.warning("No chunks found for active golden_id %s", golden_id)
            # Re-trigger ingestion (emit an event for the ingestion pipeline)
            events.append({"event": "source.reingest_needed", "golden_id": golden_id})
            continue

        for chunk in chunks:
            drift = {}
            for field in ("classification_label", "content_class", "permitted_apps"):
                if chunk.get(field) != record.get(field):
                    drift[field] = record[field]
            if drift:
                stale += 1
                enqueue_event("source.attrs_changed", {"golden_id": golden_id, "changed_fields": drift})
                events.append({"event": "source.attrs_changed", "golden_id": golden_id, "fields": list(drift)})

    # Check for orphaned chunks (golden_id in index but not in catalog)
    index_golden_ids = vector_store.distinct_golden_ids()
    for gid in index_golden_ids:
        if gid not in catalog_ids:
            orphaned += 1
            enqueue_event("source.retired", {"golden_id": gid})
            events.append({"event": "source.retired", "golden_id": gid})

    return DriftReport(orphaned, stale, missing, events)
